16	import type { Product } from "@/lib/types";
17	import { AdjustmentControls } from "./AdjustmentControls";
18	import { PreviewTable } from "./PreviewTable";
19	import { ProductList } from "./ProductList";
20	import {
21	  ProductSearchFilters,
22	  type ProductFilterState,
23	} from "./ProductSearchFilters";
24	import {
25	  useProfileForm,
26	  useProfileFormActions,
27	  type ProductScope,
28	} from "./ProfileFormProvider";
29	
30	type Props = {
31	  initialProducts: Product[];
32	  categories: string[];
33	  segments: string[];
34	  brands: string[];
35	};
36	
37	const emptyFilters: ProductFilterState = {
38	  q: "",
39	  sku: "",
40	  category: "",
41	  segment: "",
42	  brand: "",
43	};
44	
45	const fetcher = (url: string) =>
46	  fetch(url).then((r) => r.json() as Promise<{ products: Product[] }>);
47	
48	export function SelectProductPricingCard({
49	  initialProducts,
50	  categories,
51	  segments,
52	  brands,
53	}: Props) {
54	  const { state } = useProfileForm();
55	  const { setScope, toggleProduct, setProducts, setAdjustment } =
56	    useProfileFormActions();
57	
58	  const [filters, setFilters] = useState<ProductFilterState>(emptyFilters);
59	  const deferredFilters = useDeferredValue(filters);
60	
61	  const swrKey = useMemo(() => {
62	    const sp = new URLSearchParams();
63	    if (deferredFilters.q) sp.set("q", deferredFilters.q);
64	    if (deferredFilters.category) sp.set("category", deferredFilters.category);
65	    if (deferredFilters.segment) sp.set("segment", deferredFilters.segment);
66	    if (deferredFilters.brand) sp.set("brand", deferredFilters.brand);
67	    return `/api/products?${sp.toString()}`;
68	  }, [deferredFilters]);
69	
70	  const { data } = useSWR(swrKey, fetcher, {
71	    fallbackData: { products: initialProducts },
72	    keepPreviousData: true,
73	  });
74	
75	  // Client-side SKU substring filter (server `q` already searches title + sku;
76	  // the dedicated SKU input is a tighter filter the user can stack on top).
77	  const products = useMemo(() => {
78	    const all = data?.products ?? [];
79	    if (!filters.sku) return all;
80	    const needle = filters.sku.trim().toLowerCase();
81	    return all.filter((p) => p.sku.toLowerCase().includes(needle));
82	  }, [data, filters.sku]);
83	
84	  const selectedIds = useMemo(
85	    () => new Set(state.selectedProductIds),
86	    [state.selectedProductIds],
87	  );
88	
89	  const visibleIds = useMemo(() => products.map((p) => p.id), [products]);
90	  const allVisibleSelected =
91	    visibleIds.length > 0 && visibleIds.every((id) => selectedIds.has(id));
92	
93	  const selectedProducts = useMemo(() => {
94	    const lookup = new Map(
95	      [...initialProducts, ...products].map((p) => [p.id, p] as const),
96	    );
97	    return state.selectedProductIds
98	      .map((id) => lookup.get(id))
99	      .filter((p): p is Product => Boolean(p));
100	  }, [initialProducts, products, state.selectedProductIds]);
101	
102	  const activeFilterChips = [
103	    filters.category && { key: "category", label: filters.category },
104	    filters.segment && { key: "segment", label: filters.segment },
105	    filters.brand && { key: "brand", label: filters.brand },
106	  ].filter(Boolean) as { key: string; label: string }[];
107	
108	  const toggleSelectAll = () => {
109	    if (allVisibleSelected) {
110	      // Deselect only the visible products; keep selections from other filters intact.
111	      setProducts(
112	        state.selectedProductIds.filter((id) => !visibleIds.includes(id)),
113	      );
114	    } else {
115	      const next = new Set(state.selectedProductIds);
116	      for (const id of visibleIds) next.add(id);
117	      setProducts(Array.from(next));
118	    }
119	  };
120	
121	  return (
122	    <Card>
123	      <CardHeader>
124	        <div className="flex items-start justify-between gap-4">
125	          <div>
126	            <h2 className="text-base font-semibold">Select Product Pricing</h2>
127	            <p className="text-sm text-muted-foreground">Set details</p>
128	          </div>
129	          <Badge variant="secondary" className="shrink-0">
130	            {state.selectedProductIds.length} selected
131	          </Badge>
132	        </div>
133	      </CardHeader>
134	      <CardContent className="space-y-6">
135	        <div className="space-y-2">
136	          <Label>You are creating a Pricing Profile for</Label>
137	          <RadioGroup
138	            value={state.scope}
139	            onValueChange={(v) => setScope(v as ProductScope)}
140	            className="flex flex-wrap gap-6"
141	          >
142	            <ScopeRow id="scope-one" value="one" label="One Product" />
143	            <ScopeRow
144	              id="scope-multiple"
145	              value="multiple"
146	              label="Multiple Products"
147	            />
148	            <ScopeRow id="scope-all" value="all" label="All Products" />
149	          </RadioGroup>
150	        </div>
151	
152	        <div className="space-y-2">
153	          <Label>Search for Products</Label>
154	          <ProductSearchFilters
155	            value={filters}
156	            onChange={setFilters}
157	            categories={categories}
158	            segments={segments}
159	            brands={brands}
160	          />
161	        </div>
162	
163	        <div className="flex flex-wrap items-center gap-2 text-sm">
164	          <span className="text-muted-foreground">
165	            Showing ({products.length} Result{products.length === 1 ? "" : "s"})
166	            {filters.q || filters.sku ? " for " : ""}
167	          </span>
168	          {(filters.q || filters.sku) && (
169	            <Badge variant="outline">
170	              {filters.q || filters.sku} (Product Name or SKU Code)
171	            </Badge>
172	          )}
173	          {activeFilterChips.map((chip) => (
174	            <Badge key={chip.key} variant="outline">
175	              {chip.label}
176	            </Badge>
177	          ))}
178	        </div>
179	
180	        <div className="flex items-center gap-4 text-sm">
181	          <button
182	            type="button"
183	            onClick={toggleSelectAll}
184	            className="font-medium text-primary hover:underline"
185	          >
186	            {allVisibleSelected ? "Deselect All" : "Select all"}
187	          </button>
188	          {state.selectedProductIds.length > 0 && (
189	            <span className="text-muted-foreground">
190	              You&apos;ve selected {state.selectedProductIds.length} product
191	              {state.selectedProductIds.length === 1 ? "" : "s"}, these will be
192	              added to this profile
193	            </span>
194	          )}
195	        </div>
196	
197	        <ProductList
198	          products={products}
199	          selectedIds={selectedIds}
200	          onToggle={toggleProduct}
201	        />
202	
203	        <Separator />
204	
205	        <AdjustmentControls
206	          adjustment={state.adjustment}
207	          onChange={setAdjustment}
208	        />
209	
210	        <div className="flex items-center justify-between">
211	          <p className="text-sm font-medium">Preview new prices</p>
212	          <Button variant="ghost" size="sm" className="text-primary">
213	            <RefreshCcw className="mr-1 size-3.5" />
214	            Refresh New Price Table
215	          </Button>
216	        </div>
217	
218	        <PreviewTable
219	          products={selectedProducts}
220	          adjustment={state.adjustment}
221	        />
222	
223	        <div className="flex items-center justify-between pt-2">
224	          <span className="text-xs text-muted-foreground">
225	            Your entries are saved automatically
226	          </span>
227	          <div className="flex items-center gap-2">
228	            <Button
229	              variant="ghost"
230	              onClick={() => scrollToCard("profile-basic-card")}
231	            >
232	              Back
233	            </Button>
234	            <Button onClick={() => scrollToCard("assign-customers-card")}>
235	              Next
236	            </Button>
237	          </div>
238	        </div>
239	      </CardContent>
240	    </Card>
241	  );
242	}
243	
244	function scrollToCard(id: string) {
245	  document
246	    .getElementById(id)
247	    ?.scrollIntoView({ behavior: "smooth", block: "start" });
248	}
249	
250	function ScopeRow({
251	  id,
252	  value,
253	  label,
254	}: {
255	  id: string;
256	  value: ProductScope;
257	  label: string;
258	}) {
259	  return (
